import itertools

class Solution:
    def earliestFullBloom(self, plantTime, growTime):
        n = len(plantTime)
        best = None
        for perm in itertools.permutations(range(n)):
            cumulative = 0
            worst = 0
            for i in perm:
                cumulative += plantTime[i]
                bloom = cumulative + growTime[i]
                if bloom > worst:
                    worst = bloom
            if best is None or worst < best:
                best = worst
        return best

