class Solution:
    def earliestFullBloom(self, plantTime, growTime):
        order = sorted(range(len(plantTime)), key=lambda i: -growTime[i])
        cumulative = 0
        best = 0
        for i in order:
            cumulative += plantTime[i]
            bloom = cumulative + growTime[i]
            if bloom > best:
                best = bloom
        return best

